function escapeHtml(e){return e.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;")}function hideMessages(){const e=document.getElementById("errorBox"),t=document.getElementById("successBox");e&&(e.style.display="none"),t&&(t.style.display="none")}function showError(e){hideMessages();const t=document.getElementById("errorBox"),n=document.getElementById("errorMsg");n&&(n.textContent=e),t&&(t.style.display="block")}function showSuccess(e){hideMessages();const t=document.getElementById("successBox"),n=document.getElementById("successMsg");n&&(n.textContent=e),t&&(t.style.display="block")}function syntaxHighlight(e){return(e=e.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;")).replace(/("(\\u[\da-fA-F]{4}|\\[^u]|[^\\"])*"(\s*:)?|\b(true|false|null)\b|-?\d+(?:\.\d*)?(?:[eE][+-]?\d+)?)/g,function(e){let t="json-number";return/^"/.test(e)?t=/:$/.test(e)?"json-key":"json-string":/true|false/.test(e)?t="json-boolean":/null/.test(e)&&(t="json-null"),'<span class="'+t+'">'+e+"</span>"})}function attachCopyBtn(e,t,n){const s=document.getElementById(e);if(!s)return;const i=n||s.innerHTML;s.addEventListener("click",()=>{const e="function"==typeof t?t():document.getElementById(t)?.value||document.getElementById(t)?.textContent;navigator.clipboard.writeText(e).then(()=>{s.innerHTML='<i class="bi bi-check-lg" aria-hidden="true"></i> Copied!',setTimeout(()=>{s.innerHTML=i},2e3)},()=>{s.innerHTML='<i class="bi bi-x-lg" aria-hidden="true"></i> Failed',setTimeout(()=>{s.innerHTML=i},2e3)})})}function attachPasteBtn(e,t){const n=document.getElementById(e);if(!n)return;const s=n.innerHTML;n.addEventListener("click",()=>{navigator.clipboard.readText().then(e=>{document.getElementById(t).value=e},()=>{n.innerHTML='<i class="bi bi-x-lg" aria-hidden="true"></i> Denied',setTimeout(()=>{n.innerHTML=s},2e3)})})}